// Llamar al endpoint de embeddings configurado via AI_EMBEDDING_URL
// Si no esta configurado, usar OpenAI ada-002 con OPENAI_API_KEY
// Referencia: GHL_Database.txt seccion 'Workflow WF-AI-Enricher'

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const messages   = $input.all().map(i => i.json);
const embedUrl   = $env.AI_EMBEDDING_URL || 'https://api.openai.com/v1/embeddings';
const openaiKey  = $env.OPENAI_API_KEY;

if (!openaiKey && !$env.AI_EMBEDDING_URL) {
  // Sin clave de IA configurada — saltar silenciosamente
  return messages.map(m => ({ json: Object.assign({}, m, { _embedding_skip: true }) }));
}

const results = [];

// Procesar en batch de 20 para no exceder rate limit
const batchSize = 20;
for (let i = 0; i < messages.length; i += batchSize) {
  const batch = messages.slice(i, i + batchSize);
  const texts  = batch.map(m => String(m.body).substring(0, 8000));

  let resp;
  let retries = 0;
  while (retries < 3) {
    try {
      const headers = { 'Content-Type': 'application/json' };
      if (openaiKey) headers['Authorization'] = 'Bearer ' + openaiKey;

      resp = await fetch(embedUrl, {
        method:  'POST',
        headers,
        body:    JSON.stringify({ input: texts, model: 'text-embedding-ada-002' })
      });
      if (resp.status === 429) { await sleep(Math.pow(2, retries) * 2000); retries++; continue; }
      break;
    } catch (err) {
      if (retries >= 2) { break; }
      await sleep(Math.pow(2, retries) * 1000);
      retries++;
    }
  }

  if (!resp || !resp.ok) {
    // Error en API — marcar como skip para este batch
    for (const m of batch) results.push({ json: Object.assign({}, m, { _embedding_skip: true }) });
    continue;
  }

  const data = await resp.json();
  const embeddings = (data.data || []).map(e => e.embedding);

  for (let j = 0; j < batch.length; j++) {
    results.push({
      json: Object.assign({}, batch[j], { embedding: embeddings[j] || null })
    });
  }

  await sleep(200);
}

return results;

// Llamar LLM para enriquecer ai_intent y ai_sentiment
// Endpoint configurable via AI_LLM_URL
// Si no esta configurado, saltar silenciosamente

const llmUrl    = $env.AI_LLM_URL;
const openaiKey = $env.OPENAI_API_KEY;

if (!llmUrl && !openaiKey) {
  return $input.all().map(i => ({ json: Object.assign({}, i.json, { _llm_skip: true }) }));
}

const endpoint = llmUrl || 'https://api.openai.com/v1/chat/completions';
const results  = [];

for (const item of $input.all()) {
  const m = item.json;
  if (m._embedding_skip) { results.push(item); continue; }

  const prompt = `Analiza este mensaje de WhatsApp/SMS de un lead y responde en JSON con exactamente estos campos:
- intent: una de [purchase_intent, support, information, complaint, appointment_request, pricing_inquiry, other]
- sentiment: una de [positive, neutral, negative]
- is_question: true o false

Mensaje: "${String(m.body || '').substring(0, 500)}"

Responde solo JSON, sin explicacion.`;

  let llmResult = { intent: null, sentiment: null, is_question: null };
  try {
    const headers = { 'Content-Type': 'application/json' };
    if (openaiKey) headers['Authorization'] = 'Bearer ' + openaiKey;

    const resp = await fetch(endpoint, {
      method:  'POST',
      headers,
      body:    JSON.stringify({
        model:       'gpt-4o-mini',
        messages:    [{ role: 'user', content: prompt }],
        temperature: 0,
        max_tokens:  100
      })
    });

    if (resp.ok) {
      const data = await resp.json();
      const text = data.choices?.[0]?.message?.content || '{}';
      try { llmResult = JSON.parse(text.trim()); } catch (e) { /* ignorar parse error */ }
    }
  } catch (err) { /* ignorar errores de red */ }

  results.push({
    json: Object.assign({}, m, {
      ai_intent:      llmResult.intent     || null,
      ai_sentiment:   llmResult.sentiment  || null,
      ai_is_question: llmResult.is_question !== undefined ? Boolean(llmResult.is_question) : null
    })
  });
}

return results;
